data ← [3, 7, 1, 9, 4, 6]
count ← 0
FOR EACH item IN data
{
   IF (item > 5)
   {
      count ← count + 1
   }
}
DISPLAY(count)

temperatures ← [72, 68, 75, 80, 65, 71, 78]
max ← temperatures[1]
FOR EACH temp IN temperatures
{
   IF (temp > max)
   {
      max ← temp
   }
}
DISPLAY(max)

nums ← [4, 7, 2, 9, 3, 8, 1]
result ← 0
FOR EACH n IN nums
{
   IF (n MOD 2 = 0)
   {
      result ← result + n
   }
}
DISPLAY(result)

grades ← [90, 85, 92, 78, 88, 94, 76, 89]
count ← 0
FOR EACH g IN grades
{
   IF (g >= 90)
   {
      count ← count + 1
   }
}
DISPLAY(count)

data ← [5, 12, 3, 8, 15, 7, 20, 4]
threshold ← 10
result ← []
FOR EACH item IN data
{
   IF (item > threshold)
   {
      APPEND(result, item)
   }
}
DISPLAY(LENGTH(result))

prices ← [12, 45, 8, 23, 67, 34, 5, 78, 19, 42]
total ← 0
count ← 0
FOR EACH p IN prices
{
   IF (p >= 20 AND p <= 50)
   {
      total ← total + p
      count ← count + 1
   }
}
DISPLAY(count)
